import os
import uuid
import boto3
from boto3.dynamodb.conditions import Attr

class TaskRepository:
    """DynamoDB persistence for tasks."""

    def __init__(self, table_name: str = None):
        if table_name is None:
            table_name = os.environ.get('DYNAMODB_TABLE', 'tasks')
        self.table_name = table_name
        self.table = boto3.resource('dynamodb').Table(table_name)

    def save(self, task: 'Task') -> 'Task':
        if task.id is None:
            task.id = uuid.uuid4().hex
        item = {
            'id': task.id,
            'title': task.title,
            'due_date': task.due_date.isoformat(),
            'priority': task.priority,
            'status': task.status,
        }
        self.table.put_item(Item=item)
        return task

    def find(self, status: str | None = None) -> list:
        if status:
            response = self.table.scan(
                FilterExpression=Attr('status').eq(status)
            )
        else:
            response = self.table.scan()
        return [Task.from_row(item) for item in response.get('Items', [])]

from dataclasses import dataclass
from datetime import datetime

@dataclass
class Task:
    id: str | None
    title: str
    due_date: datetime
    priority: int = 2
    status: str = 'pending'

    @classmethod
    def from_row(cls, row) -> 'Task':
        return cls(
            id=row['id'],
            title=row['title'],
            due_date=datetime.fromisoformat(row['due_date']),
            priority=int(row['priority']),
            status=row['status']
        )

import os
import boto3

class EmailNotifier:
    """Sends overdue-task digest emails via Amazon SES."""

    def __init__(self):
        self.region = os.environ.get('AWS_SES_REGION', 'us-east-1')
        self.from_email = os.environ.get('SES_FROM_EMAIL', '')
        self.ses = boto3.client('ses', region_name=self.region)

    def send_overdue_digest(self, overdue: list, to: str) -> int:
        if not overdue:
            return 0
        body = 'Overdue tasks:\n' + '\n'.join(
            f'- {t.title} (due {t.due_date:%Y-%m-%d})' for t in overdue
        )
        subject = f'{len(overdue)} overdue task(s)'
        self.ses.send_email(
            Source=self.from_email,
            Destination={'ToAddresses': [to]},
            Message={
                'Subject': {'Data': subject, 'Charset': 'UTF-8'},
                'Body': {
                    'Text': {'Data': body, 'Charset': 'UTF-8'}
                }
            }
        )
        return 1

import json
import os
from datetime import datetime
from decimal import Decimal

def _serialize(obj):
    """JSON serializer for objects not serializable by default."""
    if isinstance(obj, datetime):
        return obj.isoformat()
    if isinstance(obj, Decimal):
        return int(obj) if obj % 1 == 0 else float(obj)
    raise TypeError(f'Type {type(obj)} not serializable')

def lambda_handler(event: dict, context) -> dict:
    """API Gateway proxy handler for task CRUD operations."""
    repo = TaskRepository()
    method = event.get('httpMethod', '')
    path = event.get('path', '')
    headers = {'Content-Type': 'application/json'}

    try:
        if path == '/tasks' and method == 'GET':
            params = event.get('queryStringParameters') or {}
            status = params.get('status', None)
            tasks = repo.find(status=status)
            body = json.dumps(
                [{'id': t.id, 'title': t.title, 'due_date': t.due_date,
                  'priority': t.priority, 'status': t.status}
                 for t in tasks],
                default=_serialize
            )
            return {'statusCode': 200, 'headers': headers, 'body': body}

        elif path == '/tasks' and method == 'POST':
            payload = json.loads(event.get('body') or '{}')
            task = Task(
                id=None,
                title=payload['title'],
                due_date=datetime.fromisoformat(payload['due_date']),
                priority=int(payload.get('priority', 2)),
                status=payload.get('status', 'pending')
            )
            saved = repo.save(task)
            body = json.dumps(
                {'id': saved.id, 'title': saved.title,
                 'due_date': saved.due_date, 'priority': saved.priority,
                 'status': saved.status},
                default=_serialize
            )
            return {'statusCode': 201, 'headers': headers, 'body': body}

        else:
            return {'statusCode': 405, 'headers': headers,
                    'body': json.dumps({'error': 'Method Not Allowed'})}

    except Exception as exc:
        return {'statusCode': 500, 'headers': headers,
                'body': json.dumps({'error': str(exc)})}
